public class ObjectLifecycle {
    public static void main(String[] args) {
        // 1. Object created on Heap, reference 'obj' on Stack
        MyObject obj = new MyObject();

        // 2. Object is in use — reachable via 'obj'
        obj.doWork();

        // 3. Reference reassigned — original object is now unreachable
        obj = null;
        // Original MyObject is now ELIGIBLE for GC
        // But GC may not run immediately!

        // 4. Requesting GC (only a suggestion, JVM may ignore)
        System.gc();
    }
}

