Object val = soft.get(); // may return null if collected

// Weak Reference — collected at next GC cycle
WeakReference<Object> weak = new WeakReference<>(new Object());
Object val2 = weak.get(); // likely null after GC

// Phantom Reference — for post-mortem cleanup
ReferenceQueue<Object> queue = new ReferenceQueue<>();
PhantomReference<Object> phantom = 
    new PhantomReference<>(new Object(), queue);
phantom.get(); // ALWAYS returns null

