public class BankAccount {
    private double balance;  // PRIVATE — direct access blocked
    private final String accountId;

    public BankAccount(String accountId, double initialBalance) {
        if (initialBalance < 0) throw new IllegalArgumentException("Negative initial balance");
        this.accountId = accountId;
        this.balance = initialBalance;
    }

    // Controlled access — invariant enforced
    public void withdraw(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Amount must be positive");
        if (amount > balance) throw new InsufficientFundsException();
        balance -= amount;
    }

    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Amount must be positive");
        balance += amount;
    }

    public double getBalance() { return balance; }  // Read-only access
    public String getAccountId() { return accountId; }  // Immutable field
}

