// FRAGILE: Inheritance — Stack exposes ArrayList methods
class BadStack extends ArrayList<Object> {
    // Users can call add(index, element), remove(index), etc.
    // Completely breaks Stack abstraction!
}

// BETTER: Composition — full control over API
class Stack<T> {
    private final List<T> items = new ArrayList<>();  // has-a

    public void push(T item) { items.add(item); }
    public T pop() {
        if (isEmpty()) throw new EmptyStackException();
        return items.remove(items.size() - 1);
    }
    public T peek() {
        if (isEmpty()) throw new EmptyStackException();
        return items.get(items.size() - 1);
    }
    public boolean isEmpty() { return items.isEmpty(); }
    public int size() { return items.size(); }
    // Only stack operations exposed — no ArrayList leakage
}

