public final class ImmutablePerson {
    // Step 2: private final fields
    private final String name;
    private final int age;
    private final List<String> hobbies;
    private final Date birthDate;

    public ImmutablePerson(String name, int age, List<String> hobbies, Date birthDate) {
        this.name = name;  // String is already immutable
        this.age = age;    // primitives are safe
        // Step 4: Defensive copy in constructor
        this.hobbies = List.copyOf(hobbies);  // unmodifiable copy
        this.birthDate = new Date(birthDate.getTime()); // deep copy
    }

    // Step 3: No setters — only getters
    public String getName() { return name; }
    public int getAge() { return age; }

    // Step 5: Defensive copy in getters
    public List<String> getHobbies() {
        return Collections.unmodifiableList(hobbies);
    }
    public Date getBirthDate() {
        return new Date(birthDate.getTime()); // return copy
    }
}

