// Old style — fall-through prone
switch (day) {
    case MONDAY:
    case FRIDAY:
        System.out.println("Work hard");
        break; // forget this and you get fall-through!
    case SATURDAY:
        System.out.println("Rest");
        break;
}

// New style — expression with arrow syntax
String activity = switch (day) {
    case MONDAY, FRIDAY -> "Work hard";
    case SATURDAY, SUNDAY -> "Rest";
    default -> "Normal day";
};

// With yield for complex blocks
int result = switch (status) {
    case "SUCCESS" -> 1;
    case "RETRY" -> {
        log("Retrying...");
        yield 0;  // yield returns value from block
    }
    default -> -1;
};

// Old style — verbose and error-prone
if (obj instanceof String) {
    String s = (String) obj;
    System.out.println(s.length());
}

// New style — pattern variable binding
if (obj instanceof String s) {
    System.out.println(s.length()); // s is already cast
}

// With negation — variable scoped to else
if (!(obj instanceof String s)) {
    return; // s is NOT in scope here
}
// s IS in scope here (flow scoping)
System.out.println(s.toUpperCase());

// Guard conditions
if (obj instanceof String s && s.length() > 5) {
    System.out.println("Long string: " + s);
}

// Switch pattern matching (Java 21)
String result = switch (obj) {
    case Integer i -> "Int: " + i;
    case String s when s.length() > 5 -> "Long string";
    case String s -> "Short: " + s;
    case null -> "null";
    default -> "Unknown";
};

